class KP {
  hh: string = ""
  smn: string = ""
}

function s2(ily: string): KP {
  let hh: KP = {hh: "", smn: ""}
  for (let i: number = 0; i < ily.length; i++) {
    if (i % 2 == 0) {
      hh.hh = hh.hh + ily[i]
    } else {
      hh.smn = hh.smn + ily[i]
    }
  }
  return hh
}

